instruction:
Plain objects only support string (and symbol) keys. `Map` supports ANY key type — objects, arrays, functions, numbers.

Map also remembers insertion order and has a clean API:

```js
const m = new Map();
m.set(key, value);
m.get(key);
m.has(key);
m.delete(key);
m.size;
```

starter:
const scores = new Map();

const alice = { name: "Alice" };
const bob   = { name: "Bob"   };

scores.set(alice, 95);
scores.set(bob, 87);
scores.set(1, "first");  // number key!

console.log(scores.get(alice));
console.log(scores.get(bob));
console.log(scores.has(alice));
console.log(scores.size);

for (const [person, score] of scores) {
  if (typeof person === 'object') console.log(`${person.name}: ${score}`);
}

